            sUrl = "/ui/bp/fbp/op/ac/ez_202_01_01b.xml";
            popupName = "화물정보화면"
            height = 840;
        }

        let opts = {
              popupName: popupName
            , width: 1250
            , height: height
            , top: "0px"
            , left: "0px"
        }
        let data = {
              CargoType: "cont"
            , idx: idx
        }

        $c.win.openPopup(sUrl, opts, data);
    }

};

/**
 * 컨테이너 그리드 image click
 */
scwin.gr_flc_ontextimageclick = function (rowIndex, columnIndex) {

